## Threshold-ablation TU graph-classification experiments (migrated to FrameworkMain).
## Splits are referenced directly from src/simplegnn/datasets/splits/fair/ ;
## the old Data/Splits copy helper has been removed.
##
## Configs are generated by experiments/base_paper/tools/migrate_threshold_configs.py
## for thresholds 1..20, 30, 40, 50 across the lower / lower_upper / upper variants.
from pathlib import Path

import click
import joblib

from simplegnn.framework.core import FrameworkMain

CONFIG_ROOT = Path('experiments/base_paper/classification/configs/ablation/threshold')
TYPES = ['upper', 'lower_upper', 'lower']
THRESHOLDS = list(range(1, 21)) + [30, 40, 50]


def run_ablation_experiment(num_threads, threshold_type, threshold):
    config_path = CONFIG_ROOT / threshold_type / f'main_config_ablation_threshold_{threshold}.yml'
    experiment = FrameworkMain(config_path)
    experiment.preprocessing(num_threads=1)
    experiment.run_configurations(num_threads=num_threads)
    experiment.evaluate_results()
    experiment.run_best_configuration(num_threads=num_threads)
    experiment.evaluate_results(evaluate_best_model=True)


def main_ablation_threshold(num_threads=-1):
    combinations = [(num_threads, threshold_type, t) for threshold_type in TYPES for t in THRESHOLDS]
    joblib.Parallel(n_jobs=num_threads)(
        joblib.delayed(run_ablation_experiment)(*combination) for combination in combinations
    )


@click.command()
@click.option('--num_threads', default=-1, help='Number of threads to use')
def main(num_threads):
    main_ablation_threshold(num_threads)


if __name__ == '__main__':
    main()
